SELECT DISTINCT date, CAST(EXTRACT(year FROM date) AS INTEGER) AS year, CAST(EXTRACT(month FROM date) AS INTEGER) AS month, codigo_do_produto, descricao_do_produto, regiao_de_origem, uf_de_origem, regiao_do_destinatario, uf_do_destinatario, volume_l FROM (SELECT make_date(TRY_CAST(trim("ano") AS INTEGER), CASE upper(trim("mes")) WHEN 'JAN' THEN 1 WHEN 'JANEIRO' THEN 1 WHEN 'FEV' THEN 2 WHEN 'FEVEREIRO' THEN 2 WHEN 'MAR' THEN 3 WHEN 'MARÇO' THEN 3 WHEN 'MARCO' THEN 3 WHEN 'ABR' THEN 4 WHEN 'ABRIL' THEN 4 WHEN 'MAI' THEN 5 WHEN 'MAIO' THEN 5 WHEN 'JUN' THEN 6 WHEN 'JUNHO' THEN 6 WHEN 'JUL' THEN 7 WHEN 'JULHO' THEN 7 WHEN 'AGO' THEN 8 WHEN 'AGOSTO' THEN 8 WHEN 'SET' THEN 9 WHEN 'SETEMBRO' THEN 9 WHEN 'OUT' THEN 10 WHEN 'OUTUBRO' THEN 10 WHEN 'NOV' THEN 11 WHEN 'NOVEMBRO' THEN 11 WHEN 'DEZ' THEN 12 WHEN 'DEZEMBRO' THEN 12 ELSE TRY_CAST(trim("mes") AS INTEGER) END, 1) AS date, NULLIF(TRIM("codigo_do_produto"), '') AS codigo_do_produto, NULLIF(TRIM("descricao_do_produto"), '') AS descricao_do_produto, NULLIF(TRIM("regiao_de_origem"), '') AS regiao_de_origem, NULLIF(TRIM("uf_de_origem"), '') AS uf_de_origem, NULLIF(TRIM("regiao_do_destinatario"), '') AS regiao_do_destinatario, NULLIF(TRIM("uf_do_destinatario"), '') AS uf_do_destinatario, TRY_CAST(replace(replace(trim("volume_l"), '.', ''), ',', '.') AS DOUBLE) AS volume_l FROM "anp-brazil-mdpg-lubrificante") WHERE date IS NOT NULL AND (volume_l IS NOT NULL)
